INSERT IGNORE INTO posts (title, slug, body, excerpt, pillar, published, publishedAt, createdAt, updatedAt) VALUES 
('When God Bless America Replaces Thy Kingdom Come', 'when-god-bless-america-replaces-thy-kingdom-come', 'How Patriotism Became Our Practical Savior. Patriotism has become the practical savior in American Christianity, replacing the kingdom of God as the organizing principle of faith and practice. This essay examines how this shift has shaped American church culture and what it means for authentic Christian witness.', 'How Patriotism Became Our Practical Savior. A direct examination of how patriotism has replaced the kingdom of God as the practical savior in American Christianity.', 'Prophetic Justice', 1, NOW(), NOW(), NOW()),
('The Monster in the Mirror', 'the-monster-in-the-mirror', 'Why Every Generation Gets the Bible Wrong, Why Yours Is No Different, and What to Do About It. Every generation believes it has finally gotten the Bible right, while all previous generations got it wrong. This essay explores why that pattern persists, how cultural assumptions shape biblical interpretation, and what we can do to recognize our own blind spots.', 'Why Every Generation Gets the Bible Wrong, Why Yours Is No Different, and What to Do About It. An exploration of how each generation interprets Scripture through its own cultural lens.', 'Theological Depth', 1, NOW(), NOW(), NOW());
INSERT INTO site_settings (settingKey, settingValue, updatedAt) VALUES 
('substackUrl', 'https://substack.com/@jamesbell333289?r=6hl3j&utm_medium=ios&utm_source=stories&shareImageVariant=blur', NOW()),
