INSERT INTO site_settings (settingKey, settingValue) VALUES ('aboutContent', 'James C. Bell is a pastor, author, and ministry leader whose work spans local church leadership, global pastoral training, and public theological writing. He serves as Lead Pastor of First Baptist Church of Fenton in Fenton, Michigan, where he has shepherded the congregation since 2016. He is the husband of Susanna and the father of five sons. James is the founder of the Pastors Connection Network (PCN), a national and international ministry dedicated to connecting, mentoring, and equipping pastors and churches for sustainable, faithful ministry. James is the founder of LiveWell, a writing and ministry platform committed to biblical depth, cultural clarity, and prophetic honesty. At his core, James Bell is a pastor.') ON DUPLICATE KEY UPDATE settingValue = VALUES(settingValue);
INSERT INTO site_settings (settingKey, settingValue) VALUES ('aboutImage', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663366638960/KoRED62UaUJB6FH9jFpuEG/IMG_4533_137f3486.jpeg') ON DUPLICATE KEY UPDATE settingValue = VALUES(settingValue);
INSERT IGNORE INTO posts (title, slug, body, excerpt, pillar, readTime, published, publishedAt) VALUES ('Not Persecuted—Seduced: The Crisis of American Christianity', 'not-persecuted-seduced-crisis-american-christianity', 'INTRODUCTION: Not Persecuted—Seduced. The crisis facing American Christianity is not primarily numerical. It is not about attendance decline or shrinking affiliation. American Christianity is not being persecuted. It is being seduced. And seduction is far more dangerous than persecution. Persecution clarifies allegiance. It forces a choice. It strips away ambiguity. Seduction does the opposite. Seduction confuses allegiance. Seduction tells you that you can keep Jesus and keep power, keep worship and keep control, keep the cross and keep the sword. We are not watching the church get crushed by the state. We are watching parts of the church crawl into bed with it. The prophets called it zanah. In the book of Hosea, God accuses Israel not of atheism but of adultery. Israel still worshiped. They still sacrificed. They still gathered in the temple. But when fear rose, when Assyria threatened, when political uncertainty came, they ran to foreign alliances for protection. They looked to treaties, chariots, and kings to secure what God had promised to secure.', 'The crisis facing American Christianity is not primarily numerical. American Christianity is not being persecuted. It is being seduced. And seduction is far more dangerous than persecution.', 'Prophetic Disruption', '12 min read', 1, NOW());
INSERT IGNORE INTO posts (title, slug, body, excerpt, pillar, readTime, published, publishedAt) VALUES ('You Are Not the Exception: Understanding Biblical Interpretation', 'you-are-not-the-exception', 'From The Monster in the Mirror: Every generation believes it is the exception to the rules of biblical interpretation. Every generation is convinced that they finally understand Scripture correctly. But history proves otherwise. The Pharisees were certain. The medieval church was certain. The Reformers were certain. American evangelicals are certain. And we are wrong about more than we are right about. The Bible does not change. But our interpretation of it does. And the room you''re in—your culture, your fears, your assumptions, your political moment—shapes how you read Scripture. This is not a problem to solve. It is a condition to acknowledge. The question is not whether you will be wrong. The question is whether you will be humble about it.', 'Every generation believes it is the exception to the rules of biblical interpretation. But the Bible assumes you will be wrong.', 'Theological Depth', '9 min read', 1, NOW());
INSERT INTO site_settings (settingKey, settingValue) VALUES ('pastorsNetworkContent', 'The Pastors Connection Network (PCN) is a national and international ministry dedicated to connecting, mentoring, and equipping pastors and churches for sustainable, faithful ministry. PCN operates from the conviction that pastoral isolation is one of the most underaddressed crises in the church today, and that every pastor—regardless of geography, denomination, or resources—deserves genuine community and meaningful development. Through PCN, we lead pastoral training initiatives reaching national church leaders serving in some of the most remote and underresourced regions in the world, with active partnerships in India, Thailand, Pakistan, South America, and across Africa. Our mission is straightforward: equip every pastor, resource every church, and carry the gospel to the last unreached corner of the earth. Join a community of pastors committed to faithful ministry, theological depth, and kingdom advancement.') ON DUPLICATE KEY UPDATE settingValue = VALUES(settingValue);
